const repostMutation = useRepostMutation(token);
```

**Add handler functions** (after `handleReact` around line 132):
```typescript
const handleComment = (journalId: string) => {
  navigation.navigate('PostDetail', {journalId});
};

const handleBookmark = (journalId: string) => {
  if (!token) return;
  bookmarkMutation.mutate(journalId);
};

const handleRepost = (journalId: string) => {
  if (!token) return;
  Alert.alert(
    'Repost',
    'Repost this to your feed?',
    [
      {text: 'Cancel', style: 'cancel'},
      {text: 'Repost', onPress: () => repostMutation.mutate(journalId)},
    ],
  );
};
```

**Wire to PostCard** in the `renderItem` (around line 258-277). Add three props alongside the existing `onReact`:
```typescript
<PostCard
  // ... existing props stay the same ...
  isBookmarked={!!item.has_bookmarked}   // NEW: pass bookmark state
  onReact={type => handleReact(item.id, receiverId, type)}
  onComment={() => handleComment(item.id)}       // NEW
  onBookmark={() => handleBookmark(item.id)}     // NEW
  onRepost={() => handleRepost(item.id)}         // NEW
  onPress={() => navigation.navigate('PostDetail', {journalId: item.id})}
  onAuthorPress={handleAuthorPress}
/>
```

Note: `isBookmarked` is already on the PostCard props interface (line 23 of PostCard.tsx) and flows through to ActionBar. It was just never passed from the feed. The `has_bookmarked` field exists on `JournalItem` (line 22 of mobileApi.ts) -- it depends on whether the server returns it for the feed endpoint. If the server does not return `has_bookmarked` for the general feed endpoint, then it will be `undefined` and the bookmark icon will show as un-bookmarked, which is acceptable default behavior and will correct itself after the first toggle.

---

#### Step 3: Update `ProfileWritingsTab.tsx`

**Imports to add:**
```typescript
import {Alert} from 'react-native';
import {useMutation} from '@tanstack/react-query';
import {socialApi} from '../../lib/api/socialApi';
import {queryClient} from '../../lib/queryClient';
import {useBookmarkMutation, useRepostMutation} from '../../hooks/useSocialMutations';
```

**Instantiate the hooks** (inside the component, after `token` declaration, around line 30):
```typescript
const bookmarkMutation = useBookmarkMutation(token, ['profileWritings', userId]);
const repostMutation = useRepostMutation(token);
```

**Also add a reactionMutation** -- ProfileWritingsTab currently has NO reaction handler at all. This is needed for the Like/React button:
```typescript
const reactionMutation = useMutation({
  mutationFn: async ({
    journalId,
    receiverId,
    reactionType,
  }: {
    journalId: string;
    receiverId: string;
    reactionType: string;
  }) => {
    if (!token) throw new Error('Please log in to react.');
    return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
  },
  onMutate: async ({journalId, reactionType}) => {
    await queryClient.cancelQueries({queryKey: ['profileWritings', userId]});
    const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
      ['profileWritings', userId],
    );
    if (prev) {
      queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
        ['profileWritings', userId],
        old => {
          if (!old) return old;
          return {
            ...old,
            pages: old.pages.map(page => ({
              ...page,
              data: page.data.map(item => {
                if (item.id !== journalId) return item;
                const removing = item.user_reaction === reactionType;
                const currentCount =
                  (item.reaction_count?.[0]?.count ??
                    item.like_count?.[0]?.count ??
                    item.likes_count ??
                    0) as number;
                const delta = removing ? -1 : item.user_reaction ? 0 : 1;
                return {
                  ...item,
                  user_reaction: removing ? null : reactionType,
                  has_liked: !removing,
                  like_count: [{count: Math.max(0, currentCount + delta)}],
                };
              }),
            })),
          };
        },
      );
    }
    return {prev};
  },
  onError: (_err, _vars, context) => {
    if (context?.prev) {
      queryClient.setQueryData(['profileWritings', userId], context.prev);
    }
  },
  onSettled: () => {
    queryClient.invalidateQueries({queryKey: ['profileWritings', userId]});
  },
});
```

This is essentially the same reactionMutation from HomeFeedScreen but keyed to `['profileWritings', userId]`.

**Add handler functions:**
```typescript
const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
  if (!token) return;
  reactionMutation.mutate({journalId, receiverId, reactionType});
};

const handleComment = (journalId: string) => {
  navigation.navigate('PostDetail', {journalId});
};

const handleBookmark = (journalId: string) => {
  if (!token) return;
  bookmarkMutation.mutate(journalId);
};

const handleRepost = (journalId: string) => {
  if (!token) return;
  Alert.alert(
    'Repost',
    'Repost this to your feed?',
    [
      {text: 'Cancel', style: 'cancel'},
      {text: 'Repost', onPress: () => repostMutation.mutate(journalId)},
    ],
  );
};
```

**Wire to PostCard** in the `renderItem` (around line 99-117). Add the missing props:
```typescript
const receiverId = item.user_id ?? item.users?.id ?? '';

return (
  <PostCard
    // ... existing props stay the same ...
    isBookmarked={!!item.has_bookmarked}                        // NEW
    onReact={type => handleReact(item.id, receiverId, type)}    // NEW
    onComment={() => handleComment(item.id)}                    // NEW
    onBookmark={() => handleBookmark(item.id)}                  // NEW
